static int treeHeight(struct TreeNode* node, int left) {
    int h = 0;
    while (node) { h++; node = left ? node->left : node->right; }
    return h;
}
int countNodes(struct TreeNode* root) {
    if (!root) return 0;
    int lh = treeHeight(root, 1), rh = treeHeight(root, 0);
    if (lh == rh) return (1 << lh) - 1;
    return 1 + countNodes(root->left) + countNodes(root->right);
}
